"use strict";(self.webpackChunkwoocommerce_ebay_connector=self.webpackChunkwoocommerce_ebay_connector||[]).push([[101],{6887(t,e,a){a.r(e),a.d(e,{comp:()=>y,data:()=>f});var r=a(641);const o=a.p+"assets/img/general-setting.c4907b70.webp",i=a.p+"assets/img/general-setting-2.0f8684c8.webp",s=a.p+"assets/img/general-order-import-seeting.ed202a98.webp",n=a.p+"assets/img/return-policy.ef7201e9.webp",d=a.p+"assets/img/shipping.1a7be4f3.webp",c=a.p+"assets/img/dispatch.51a39faa.webp",l=a.p+"assets/img/international-shipping.ad980b32.webp",p=a.p+"assets/img/domestic-shipping.e4b7d71a.webp",h=a.p+"assets/img/Real-time-sync-setting.95b1763a.webp",m=a.p+"assets/img/woo-to-ebay.79b93944.webp",g=a.p+"assets/img/price-rule-filed.ac5aef54.webp",u=a.p+"assets/img/price-list.db423a37.webp",b={},y=(0,a(6262).A)(b,[["render",function(t,e){return(0,r.uX)(),(0,r.CE)("div",null,[...e[0]||(e[0]=[(0,r.Fv)('<h1 id="configuration-–-woocommerce-ebay-connector" tabindex="-1"><a class="header-anchor" href="#configuration-–-woocommerce-ebay-connector"><span>Configuration – WooCommerce eBay Connector</span></a></h1><p>After successful installation and account setup, configure the plugin settings by navigating to <strong>WC eBay Connector → eBay Settings</strong>.</p><hr><p><a class="doc-image-link" href="./assets/general-setting.webp"><img src="'+o+'" alt="screenshots"></a></p><h2 id="general-settings" tabindex="-1"><a class="header-anchor" href="#general-settings"><span>General Settings</span></a></h2><h3 id="product-import-settings" tabindex="-1"><a class="header-anchor" href="#product-import-settings"><span>Product Import Settings</span></a></h3><p><a class="doc-image-link" href="./assets/general-setting-2.webp"><img src="'+i+'" alt="screenshots"></a></p><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Default Category</td><td>If an eBay category isn&#39;t mapped in WooCommerce, products are placed in this default category</td></tr><tr><td>eBay Imported Order Status</td><td>Set default order status for orders imported from eBay</td></tr><tr><td>Default Product Quantity</td><td>Set the default product quantity for a product exported to eBay if the product quantity is zero in the store</td></tr><tr><td>Email Address for Report</td><td>Enter the email address to receive reports of every update sync</td></tr><tr><td>Pin code of Item Location</td><td>Enter the pincode of the item location</td></tr><tr><td>Global Shipping</td><td>Select Yes/No for global shipping depending on business need</td></tr><tr><td>Default Condition for Exported Product</td><td>If no product condition is selected, this default condition will be applied to exported products</td></tr><tr><td>Create Active Listing Only</td><td>Select <strong>Yes</strong> to create active listings only, else select <strong>No</strong></td></tr><tr><td>Create Fixed Price Listing</td><td>Select <strong>All Products</strong> or <strong>Fixed Price Products</strong></td></tr><tr><td>Product Image Import</td><td>Select <strong>In the Background</strong> (faster for large imports) or <strong>During Product Import</strong></td></tr><tr><td>Product Import Only from Global Site</td><td>If enabled, only products belonging to the eBay global site chosen in settings will be imported</td></tr></tbody></table><blockquote><p><strong>Note:</strong> For large numbers of product imports, it is advisable to keep the <strong>Product Image Import</strong> setting as <strong>In the Background</strong> to import products at a faster pace.</p></blockquote><hr><h3 id="product-export-settings" tabindex="-1"><a class="header-anchor" href="#product-export-settings"><span>Product Export Settings</span></a></h3><p><a class="doc-image-link" href="./assets/general-order-import-seeting.webp"><img src="'+s+'" alt="screenshots"></a></p><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Default Product Quantity</td><td>Set the default quantity to export to eBay if the product quantity on store is zero</td></tr><tr><td>Pin code of Item Location</td><td>Enter the pin code of the item location</td></tr><tr><td>Global Shipping</td><td>Select Yes or No as per business requirement</td></tr><tr><td>Default Condition</td><td>Select the default condition of the product listing when exported to eBay (New, Open Box, Manufacturer Refurbished, Seller Refurbished, Used, etc.)</td></tr></tbody></table><hr><h3 id="auto-mapping" tabindex="-1"><a class="header-anchor" href="#auto-mapping"><span>Auto Mapping</span></a></h3><p><strong>Enable Auto Mapping:</strong> Enable or disable the category auto-mapping feature.</p><p><a class="doc-image-link" href="./assets/general-order-import-seeting.webp"><img src="'+s+'" alt="screenshots"></a></p><p><strong>Auto Order Import:</strong> Select the condition for auto order import. It executes every 10 minutes and retrieves orders placed within the last 15 minutes.</p><blockquote><p><strong>Note:</strong> All products must be imported for real-time order import.</p></blockquote><hr><h2 id="return-policy" tabindex="-1"><a class="header-anchor" href="#return-policy"><span>Return Policy</span></a></h2><p><a class="doc-image-link" href="./assets/return-policy.webp"><img src="'+n+'" alt="screenshots"></a></p><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Define Return Policy</td><td>Select <strong>Returns Accepted</strong> or <strong>Not Accepted</strong> (for exported products)</td></tr><tr><td>Refund Option</td><td>Select <strong>Money Back</strong> or <strong>Replacement</strong></td></tr><tr><td>Returns Within</td><td>Select the return duration for exported products</td></tr><tr><td>Pay By</td><td>Select who pays for the returned product – seller or buyer</td></tr><tr><td>Other Information</td><td>Write any additional information about the Return Policy</td></tr></tbody></table><hr><h2 id="shipping-listing-settings" tabindex="-1"><a class="header-anchor" href="#shipping-listing-settings"><span>Shipping / Listing Settings</span></a></h2><p><a class="doc-image-link" href="./assets/shipping.webp"><img src="'+d+'" alt="screenshots"></a></p><h3 id="listing-options" tabindex="-1"><a class="header-anchor" href="#listing-options"><span>Listing Options</span></a></h3><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Default CountryCodeType</td><td>Enter the country code type required while exporting products</td></tr><tr><td>Listing Duration</td><td>Select Good Till Canceled, 1, 3, 5, 7, 10, or 30 days</td></tr></tbody></table><h3 id="dispatch-options" tabindex="-1"><a class="header-anchor" href="#dispatch-options"><span>Dispatch Options</span></a></h3><p><a class="doc-image-link" href="./assets/dispatch.webp"><img src="'+c+'" alt="screenshots"></a></p><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Dispatch Time</td><td>Select 1, 2, 3, 4, 5, 10, 15, 20, or 30 days</td></tr></tbody></table><h3 id="international-shipping-service" tabindex="-1"><a class="header-anchor" href="#international-shipping-service"><span>International Shipping Service</span></a></h3><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Shipping Service</td><td>Select the international shipping service from the dropdown</td></tr><tr><td>Priority</td><td>Enter the priority of the shipping service</td></tr><tr><td>Cost</td><td>Enter the shipping amount that applies when syncing with eBay</td></tr><tr><td>Additional Cost</td><td>Additional shipping amount when syncing with eBay</td></tr><tr><td>Ship to Location</td><td>Select the location where international shipping services are applicable</td></tr></tbody></table><p><a class="doc-image-link" href="./assets/international-shipping.webp"><img src="'+l+'" alt="screenshots"></a></p><h3 id="domestic-shipping-options" tabindex="-1"><a class="header-anchor" href="#domestic-shipping-options"><span>Domestic Shipping Options</span></a></h3><p><a class="doc-image-link" href="./assets/domestic-shipping.webp"><img src="'+p+'" alt="screenshots"></a></p><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Priority</td><td>Enter the shipping service priority</td></tr><tr><td>Service</td><td>Select the shipping service for the WooCommerce product created on eBay</td></tr><tr><td>Cost</td><td>Set the shipping amount that applies when syncing with eBay</td></tr><tr><td>Additional Cost</td><td>Additional shipping amount (must be less than Shipping Service Cost)</td></tr><tr><td>Time Min</td><td>Set minimum shipping time for exported products</td></tr><tr><td>Time Max</td><td>Set maximum shipping time for exported products</td></tr><tr><td>Free</td><td>Select Yes or No</td></tr></tbody></table><h2 id="real-time-sync-settings" tabindex="-1"><a class="header-anchor" href="#real-time-sync-settings"><span>Real-Time Sync Settings</span></a></h2><p>Navigate to <strong>WC eBay Connector → eBay Settings → Real-Time Sync</strong> to manage synchronization settings.</p><p>The admin can enable real-time sync to update the WooCommerce store the same as the eBay store. Product information can be updated based on:</p><ul><li>Item Created</li><li>Item Revised</li><li>Item Sold-out</li><li>Item Closed</li></ul><blockquote><p><strong>Note:</strong> For real-time settings, eBay Connector does not work for sandbox credentials. <a class="doc-image-link" href="./assets/Real-time-sync-setting.webp"><img src="'+h+'" alt="screenshots"></a></p></blockquote><hr><h2 id="ebay-to-woocommerce-real-time-sync" tabindex="-1"><a class="header-anchor" href="#ebay-to-woocommerce-real-time-sync"><span>eBay to WooCommerce Real-Time Sync</span></a></h2><p>Enable the status for <strong>eBay to WooCommerce</strong> real-time sync.</p><h3 id="select-ebay-update-events" tabindex="-1"><a class="header-anchor" href="#select-ebay-update-events"><span>Select eBay Update Events</span></a></h3><table><thead><tr><th>Event</th><th>Description</th></tr></thead><tbody><tr><td>Create</td><td>When a product is added on eBay, WooCommerce syncs its category, description, title, SKU, price, stock, images, and attributes. Auction-type products import as Simple type products.</td></tr><tr><td>Revised</td><td>WooCommerce automatically updates products edited on eBay with all details including category, title, SKU, price, stock, images, and attributes.</td></tr><tr><td>Sold-out</td><td>When an item goes out of stock on eBay, WooCommerce updates its stock accordingly.</td></tr><tr><td>Closed</td><td>Deleting an item on eBay automatically reflects in WooCommerce.</td></tr><tr><td>Transaction</td><td>When an item is purchased from the eBay store, the updates get reflected in the WooCommerce store.</td></tr></tbody></table><h3 id="additional-settings" tabindex="-1"><a class="header-anchor" href="#additional-settings"><span>Additional Settings</span></a></h3><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Fields to Update</td><td>Select the attributes to update during product updates</td></tr><tr><td>Apply When</td><td>Set the condition: Auto-Synchronization, manual update, or both</td></tr><tr><td>Get email alerts</td><td>Select if you want to receive emails for sync status</td></tr><tr><td>Select eBay email alert events</td><td>Product information email will be sent based on the selected event</td></tr><tr><td>Auto-delete WooCommerce products</td><td>Enable to auto-delete WooCommerce products when the linked eBay listing ends</td></tr></tbody></table><hr><h2 id="woocommerce-to-ebay-real-time-sync" tabindex="-1"><a class="header-anchor" href="#woocommerce-to-ebay-real-time-sync"><span>WooCommerce to eBay Real-Time Sync</span></a></h2><p>Enable real-time sync between WooCommerce Store and eBay. Any updates at the WooCommerce store end will reflect at the eBay end instantly.</p><p><a class="doc-image-link" href="./assets/woo-to-ebay.webp"><img src="'+m+'" alt="screenshots"></a></p><h3 id="synced-details-woocommerce-→-ebay" tabindex="-1"><a class="header-anchor" href="#synced-details-woocommerce-→-ebay"><span>Synced Details (WooCommerce → eBay)</span></a></h3><ul><li>Images</li><li>Description</li><li>SKU</li><li>Title</li><li>Category</li><li>Condition ID</li><li>Price</li><li>Stock</li><li>Return Policy</li></ul><blockquote><p><strong>Note:</strong> For <strong>Item Sold</strong> and <strong>Refund</strong>, only stock updates will be applied.</p></blockquote><hr><h2 id="automatic-inventory-management" tabindex="-1"><a class="header-anchor" href="#automatic-inventory-management"><span>Automatic Inventory Management</span></a></h2><p>The WooCommerce eBay Connector features Automatic Inventory Management, streamlining inventory control and reducing manual work.</p><ul><li>When a product is sold or updated on eBay, WooCommerce automatically adjusts its stock.</li><li>If a product goes out of stock on eBay, it is also marked out of stock in WooCommerce.</li><li>This automatic inventory sync works both ways, based on the Real-Time Sync settings, ensuring WooCommerce changes also reflect on eBay.</li></ul><hr><h2 id="sync-compatibility" tabindex="-1"><a class="header-anchor" href="#sync-compatibility"><span>Sync Compatibility</span></a></h2><table><thead><tr><th>Product Type</th><th>eBay → WooCommerce</th><th>WooCommerce → eBay</th></tr></thead><tbody><tr><td>Simple Products</td><td>✅</td><td>✅</td></tr><tr><td>Variable Products</td><td>✅</td><td>✅</td></tr></tbody></table><hr><h2 id="separate-sync-logs" tabindex="-1"><a class="header-anchor" href="#separate-sync-logs"><span>Separate Sync Logs</span></a></h2><p>The plugin maintains separate logs for real-time sync events, allowing you to monitor and debug synchronization activity.</p><hr><h3 id="price-rule-fields" tabindex="-1"><a class="header-anchor" href="#price-rule-fields"><span>Price Rule Fields</span></a></h3><p>The store admin can add price rules for the WooCommerce products from Add Price Rule tab. <a class="doc-image-link" href="./assets/price-rule-filed.webp"><img src="'+g+'" alt="screenshots"></a></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Product Price From</td><td>Set the starting price to apply the rule</td></tr><tr><td>Product Price To</td><td>Set the last price for the applied rule</td></tr><tr><td>Price</td><td>Set the price for the price rule</td></tr><tr><td>Operation Type</td><td>Select <strong>Fixed</strong> or <strong>Percentage</strong></td></tr><tr><td>Operation</td><td>Set the price rule operation as <strong>Increase</strong> or <strong>Decrease</strong></td></tr><tr><td>Price Rule Status</td><td>Enable or disable the price rule</td></tr><tr><td>Price Rule Applicable For</td><td>Select <strong>Import</strong>, <strong>Export</strong>, or <strong>None</strong></td></tr></tbody></table><p>Click <strong>Save</strong> to create the price rule.</p><hr><h2 id="price-rule-list" tabindex="-1"><a class="header-anchor" href="#price-rule-list"><span>Price Rule List</span></a></h2><p>The created price rules for products will display in a list after saving. <a class="doc-image-link" href="./assets/price-list.webp"><img src="'+u+'" alt="screenshots"></a></p><h3 id="bulk-actions" tabindex="-1"><a class="header-anchor" href="#bulk-actions"><span>Bulk Actions</span></a></h3><p>A button to <strong>Enable</strong>, <strong>Disable</strong>, or <strong>Delete</strong> a created price rule is provided for mass action.</p><hr>',77)])])}]]),f=JSON.parse('{"path":"/documentation/configuration.html","title":"Configuration – WooCommerce eBay Connector","lang":"en-US","frontmatter":{"prev":"/documentation/ebay-account-setup.html","next":"/documentation/category-mapping.html"},"git":{"updatedTime":1774967427000,"contributors":[{"name":"shakir.hussain","username":"","email":"shakir.hussain421@webkul.in","commits":2},{"name":"aadesh","username":"","email":"aadesh.8209@webkul.in","commits":4},{"name":"nikhilsharma.qa322","username":"","email":"nikhilsharma.qa322@webkul.in","commits":1}],"changelog":[{"hash":"b0ac37d62fd38e5863a485e67c0707465c06a10a","time":1774967427000,"email":"nikhilsharma.qa322@webkul.in","author":"nikhilsharma.qa322","message":"update the content, images and add the zoom functionality and lightbox image"},{"hash":"ba6d2edb5098181920dea430c0c44bcb4f5e451b","time":1774878680000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"update images"},{"hash":"86ec3d42e91345957915d7d678cf29733245262d","time":1774624521000,"email":"shakir.hussain421@webkul.in","author":"shakir.hussain","message":"updated blog contant"},{"hash":"94dadb620956c137c8dc61e9383043aa31028e69","time":1772176578000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"update links"},{"hash":"2d5c39163a248635a79c60d8508c0716b0a11c03","time":1772114569000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"add export product"},{"hash":"a3379ad1acde7722f52940c853addb733657393e","time":1771942912000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"update images"},{"hash":"277c5a1bdc13e06551e102ee26c728b6b048e50b","time":1771481506000,"email":"shakir.hussain421@webkul.in","author":"shakir.hussain","message":"updated ebay blog and move to dev"}]},"filePathRelative":"documentation/configuration.md"}')}}]);